import React from 'react';

const Reproduction: React.FC = () => {
  return (
    <div>
      <h1>Control Reproductivo</h1>
      <div className="card">
        <p>Módulo de reproducción en desarrollo...</p>
        <p>Funcionalidades incluidas:</p>
        <ul>
          <li>Gestión de ciclos reproductivos</li>
          <li>Registro de celos</li>
          <li>Servicios y montas</li>
          <li>Control de gestaciones</li>
          <li>Registro de partos</li>
        </ul>
      </div>
    </div>
  );
};

export default Reproduction;
